"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[13956],{76089:(e,i,n)=>{n.r(i),n.d(i,{data:()=>s});const s={key:"v-1eb883d6",path:"/js/%E5%B8%B8%E7%94%A8%E4%BB%A3%E7%A0%81/%E6%93%8D%E4%BD%9C%20JSON%20%E5%B8%B8%E7%94%A8%E6%96%B9%E6%B3%95.html",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"概念",slug:"概念",children:[]},{level:2,title:"基础结构",slug:"基础结构",children:[]},{level:2,title:"数组",slug:"数组",children:[]},{level:2,title:"对象",slug:"对象",children:[]},{level:2,title:"JSON对象和JSON字符串的转换",slug:"json对象和json字符串的转换",children:[]},{level:2,title:"字符串转对象",slug:"字符串转对象",children:[]},{level:2,title:"对象转字符串",slug:"对象转字符串",children:[]},{level:2,title:"优雅的输出格式",slug:"优雅的输出格式",children:[]},{level:2,title:"JSON字符串的替换",slug:"json字符串的替换",children:[]},{level:2,title:"遍历JSON对象和JSON数组",slug:"遍历json对象和json数组",children:[]},{level:2,title:"递归遍历",slug:"递归遍历",children:[]}],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"js/常用代码/操作 JSON 常用方法.md"}},63101:(e,i,n)=>{n.r(i),n.d(i,{default:()=>l});const s=(0,n(57293).uE)('<p>转自:https://blog.csdn.net/wildye/article/details/79647709</p><h2 id="概念" tabindex="-1"><a class="header-anchor" href="#概念" aria-hidden="true">#</a> 概念</h2><p>JSON(JavaScript Object Notation) 是一种轻量级的数据交换格式，采用完全独立于语言的文本格式，是理想的数据交换格式。同时，JSON是 JavaScript 原生格式，这意味着在 JavaScript 中处理 JSON数据不须要任何特殊的 API 或工具包。</p><h2 id="基础结构" tabindex="-1"><a class="header-anchor" href="#基础结构" aria-hidden="true">#</a> 基础结构</h2><p>必须使用双引号<code>&quot;</code>包含键值</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// 键值对的集合，值的有序列表\nvar JsonObj = {&quot;name&quot;:&quot;Hannah&quot;, &quot;like&quot;:[&quot;看书&quot;, &quot;电影&quot;, &quot;晨跑&quot;]}; \n1212\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="数组" tabindex="-1"><a class="header-anchor" href="#数组" aria-hidden="true">#</a> 数组</h2><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>var jsonArr = [\n  {\n    &quot;name&quot;: &quot;tom&quot;,\n    &quot;type&quot;: &quot;cat&quot;\n  },\n  {\n    &quot;name&quot;: &quot;jack&quot;,\n    &quot;type&quot;: &quot;mouse&quot;\n  }\n]\n1234567891012345678910\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="对象" tabindex="-1"><a class="header-anchor" href="#对象" aria-hidden="true">#</a> 对象</h2><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>var jsonObj = {\n  &quot;like&quot;: [&quot;看书&quot;, &quot;电影&quot;, &quot;晨跑&quot;],\n  &quot;book&quot;: [&quot;数字城堡&quot;, &quot;刻意练习&quot;, &quot;老人与海&quot;]\n}\n12341234\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="json对象和json字符串的转换" tabindex="-1"><a class="header-anchor" href="#json对象和json字符串的转换" aria-hidden="true">#</a> JSON对象和JSON字符串的转换</h2><h2 id="字符串转对象" tabindex="-1"><a class="header-anchor" href="#字符串转对象" aria-hidden="true">#</a> 字符串转对象</h2><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>var jsonObject= JSON.parse(jsonstr);\n11\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="对象转字符串" tabindex="-1"><a class="header-anchor" href="#对象转字符串" aria-hidden="true">#</a> 对象转字符串</h2><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>var jsonstr =JSON.stringify(jsonObject);\n11\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="优雅的输出格式" tabindex="-1"><a class="header-anchor" href="#优雅的输出格式" aria-hidden="true">#</a> 优雅的输出格式</h2><p>JSON.stringify() 方法的可选参数space，可以指定缩进用的空白字符串，用于美化输出（pretty-print）space参数是个数字，它代表有多少的空格；上限为10。该值若小于1，则意味着没有空格；如果该参数没有提供（或者为null）将没有空格。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// replacer 分隔符 space 缩进\nJSON.stringify(value[, replacer [, space]])\n\nvar formatJsonStr=JSON.stringify(jsonObject,undefined, 2);\n12341234\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="json字符串的替换" tabindex="-1"><a class="header-anchor" href="#json字符串的替换" aria-hidden="true">#</a> JSON字符串的替换</h2><p>工作经常遇到这样的字符串，如下： <img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202203201449622" alt="这里写图片描述"> 需要经过替换后，才能从字符串转化成JSON对象。这里我们需要用JS实现replaceAll的功能， 将所有的 ’ &quot; ’ 替换成 ’ &quot; ’ . 代码如下,这里的gm是固定的，g表示global，m表示multiple：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>var jsonStr=jsonStr.replace(new RegExp(&#39;\\\\&quot;&#39;,&quot;gm&quot;), &#39;&quot;&#39; );\n11\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>替换后的效果如下： <img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202203201449623" alt="这里写图片描述"></p><h2 id="遍历json对象和json数组" tabindex="-1"><a class="header-anchor" href="#遍历json对象和json数组" aria-hidden="true">#</a> 遍历JSON对象和JSON数组</h2><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// 遍历JSON对象\nvar packJson  = {\n  &quot;name&quot;:&quot;Liza&quot;, \n  &quot;password&quot;:&quot;123&quot;\n};\nfor(var k in packJson ){  //遍历packJson 对象的每个key/value对,k为key\n  alert(k + &quot; &quot; + packJson[k]);\n}\n\n// 遍历JSON数组\nvar packJson = [\n  {\n    &quot;name&quot;:&quot;Liza&quot;, \n    &quot;password&quot;:&quot;123&quot;\n  },\n  {\n    &quot;name&quot;:&quot;Mike&quot;, \n    &quot;password&quot;:&quot;456&quot;\n  }\n];\nfor(var i in packJson){  //遍历packJson 数组时，i为索引\n  alert(packJson[i].name + &quot; &quot; + packJson[i].password);\n}\n12345678910111213141516171819202122231234567891011121314151617181920212223\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="递归遍历" tabindex="-1"><a class="header-anchor" href="#递归遍历" aria-hidden="true">#</a> 递归遍历</h2><p>为了实现一些复杂功能常常需要递归遍历JSON对象，这里找出两个递归的例子</p><ul><li>递归遍历JSON，遇到数组的时候，数组中有超过一个对象，删除第一个对象之后的所有对象 <img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202203201449624" alt="这里写图片描述"></li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// 返回处理后的 json字符串 \nfunction jsonParse(jsonObj) {  \n  distinctJson(jsonObj);  \n  var last=JSON.stringify(jsonObj, undefined, 2);  \n  return last;  \n}    \n      \n// 去掉 json中数组多余的项 \nfunction distinctJson(obj) {  \n  if(obj instanceof Array) {  \n    if(obj.length &gt; 1) { //数组中有超过一个对象，删除第一个对象之后的所有对象  \n      obj.splice(1, (obj.length - 1));  \n    }  \n    distinctJson(obj[0]);  \n  } else if (obj instanceof Object) {  \n    for( var index in obj){  \n      var jsonValue = obj[index];  \n      distinctJson(jsonValue);  \n    }  \n  }  \n} \n123456789101112131415161718192021123456789101112131415161718192021\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>递归查找目标节点（节点id为targetId，有且只有一个），找到后把targetChildren赋值给节点的children 举个例子，原始JSON如下，查找的目标节点id为5 <img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202203201449625" alt="这里写图片描述"> targetChildren为 <img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202203201449626" alt="这里写图片描述"> 期望最后处理的JSON结果为: <img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202203201449627" alt="这里写图片描述"></li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// 递归查找目标节点 \nfunction findTarget(obj,targetId,targetChildren) {  \n  if (obj.id==targetId) {  \n    obj.children=targetChildren;  \n    return true;  \n    } else {  \n    if(obj.children!=null){  \n      for(var i=0; i&lt;obj.children.length; i++){  \n        var flag=findTarget(obj.children[i],targetId,targetChildren);  \n        if(flag==true) return true;\n      }  \n    }  \n  }  \n    return false;  \n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>',30),a={},l=(0,n(63243).Z)(a,[["render",function(e,i){return s}]])},63243:(e,i)=>{i.Z=(e,i)=>{const n=e.__vccOpts||e;for(const[e,s]of i)n[e]=s;return n}}}]);